// Kafka Producer Configuration
@Configuration
class KafkaProducerConfig {

    @Value("${spring.kafka.bootstrap-servers:localhost:9092}")
    private String bootstrapServers;

    @Bean
    public ProducerFactory<String, String> producerFactory() {
        Map<String, Object> configProps = new HashMap<>();
        configProps.put(ProducerConfig.BOOTSTRAP_SERVERS_CONFIG, bootstrapServers);
        configProps.put(ProducerConfig.KEY_SERIALIZER_CLASS_CONFIG, StringSerializer.class);
        configProps.put(ProducerConfig.VALUE_SERIALIZER_CLASS_CONFIG, StringSerializer.class);
        configProps.put(ProducerConfig.ACKS_CONFIG, "all");
        configProps.put(ProducerConfig.RETRIES_CONFIG, 3);
        configProps.put(ProducerConfig.ENABLE_IDEMPOTENCE_CONFIG, true);
        configProps.put(ProducerConfig.MAX_IN_FLIGHT_REQUESTS_PER_CONNECTION, 5);
        return new DefaultKafkaProducerFactory<>(configProps);
    }

    @Bean
    public KafkaTemplate<String, String> kafkaTemplate() {
        return new KafkaTemplate<>(producerFactory());
    }
}

// Kafka Producer Service
@Service
class EventProducerService {

    private final KafkaTemplate<String, String> kafkaTemplate;

    @Value("${event.tracking.topic:event-tracking}")
    private String defaultTopic;

    // Well-known header prefixes that are allowed
    private static final Set<String> ALLOWED_HEADER_PREFIXES = Set.of(
            "tracking-", "user-", "x-custom-", "x-meta-", "correlation-", "session-"
    );

    private static final Set<String> ALLOWED_HEADERS = Set.of(
            "tracking-id", "user-id", "correlation-id", "session-id",
            "source-service", "event-type", "event-version", "content-type"
    );

    public EventProducerService(KafkaTemplate<String, String> kafkaTemplate) {
        this.kafkaTemplate = kafkaTemplate;
    }

    public CompletableFuture<SendResult<String, String>> sendEvent(
            String topic,
            EventMessage eventMessage,
            Map<String, String> httpHeaders) {

        String targetTopic = (topic != null && !topic.isBlank()) ? topic : defaultTopic;

        ProducerRecord<String, String> record = new ProducerRecord<>(
                targetTopic,
                eventMessage.getKey(),
                eventMessage.getPayload()
        );

        // Add headers from HTTP request headers (filtered)
        if (httpHeaders != null) {
            httpHeaders.forEach((key, value) -> {
                if (isAllowedHeader(key.toLowerCase())) {
                    record.headers().add(key.toLowerCase(), value.getBytes(StandardCharsets.UTF_8));
                }
            });
        }

        // Add custom headers from the request body
        if (eventMessage.getCustomHeaders() != null) {
            eventMessage.getCustomHeaders().forEach((key, value) -> {
                if (key != null && value != null && !key.isBlank()) {
                    record.headers().add(key, value.getBytes(StandardCharsets.UTF_8));
                }
            });
        }

        // Add system-generated metadata headers
        record.headers().add("produced-timestamp",
                String.valueOf(System.currentTimeMillis()).getBytes(StandardCharsets.UTF_8));
        record.headers().add("producer-service",
                "event-tracking-service".getBytes(StandardCharsets.UTF_8));

        return kafkaTemplate.send(record).toCompletableFuture();
    }

    private boolean isAllowedHeader(String headerName) {
        if (ALLOWED_HEADERS.contains(headerName)) {
            return true;
        }
        return ALLOWED_HEADER_PREFIXES.stream().anyMatch(headerName::startsWith);
    }

    public Map<String, String> extractHeadersMap(Headers headers) {
        Map<String, String> headerMap = new LinkedHashMap<>();
        headers.forEach(header ->
                headerMap.put(header.key(), new String(header.value(), StandardCharsets.UTF_8))
        );
        return headerMap;
    }
}

// REST Controller
@RestController
@RequestMapping("/api/v1/events")
class EventTrackingController {

    private final EventProducerService eventProducerService;

    public EventTrackingController(EventProducerService eventProducerService) {
        this.eventProducerService = eventProducerService;
    }

    @PostMapping("/publish")
    public ResponseEntity<EventResponse> publishEvent(
            @RequestBody EventMessage eventMessage,
            @RequestHeader(value = "tracking-id", required = false) String trackingId,
            @RequestHeader(value = "user-id", required = false) String userId,
            @RequestHeader(value = "correlation-id", required = false) String correlationId,
            @RequestHeader(value = "session-id", required = false) String sessionId,
            @RequestHeader(value = "source-service", required = false) String sourceService,
            @RequestHeader(value = "event-type", required = false) String eventType,
            @RequestHeader(value = "event-version", required = false) String eventVersion) {

        // Collect HTTP headers into a map
        Map<String, String> httpHeaders = new LinkedHashMap<>();
        if (trackingId != null) httpHeaders.put("tracking-id", trackingId);
        if (userId != null) httpHeaders.put("user-id", userId);
        if (correlationId != null) httpHeaders.put("correlation-id", correlationId);
        if (sessionId != null) httpHeaders.put("session-id", sessionId);
        if (sourceService != null) httpHeaders.put("source-service", sourceService);
        if (eventType != null) httpHeaders.put("event-type", eventType);
        if (eventVersion != null) httpHeaders.put("event-version", eventVersion);

        // Generate tracking-id if not provided
        if (trackingId == null || trackingId.isBlank()) {
            String generatedTrackingId = UUID.randomUUID().toString();
            httpHeaders.put("tracking-id", generatedTrackingId);
        }

        try {
            SendResult<String, String> result = eventProducerService
                    .sendEvent(null, eventMessage, httpHeaders)
                    .join();

            RecordMetadata metadata = result.getRecordMetadata();
            Map<String, String> includedHeaders = eventProducerService
                    .extractHeadersMap(result.getProducerRecord().headers());

            EventResponse response = new EventResponse(
                    "SUCCESS",
                    "Event published successfully",
                    metadata.topic(),
                    metadata.partition(),
                    metadata.offset(),
                    includedHeaders
            );

            return ResponseEntity.ok(response);

        } catch (Exception e) {
            EventResponse errorResponse = new EventResponse();
            errorResponse.setStatus("ERROR");
            errorResponse.setMessage("Failed to publish event: " + e.getMessage());
            return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR).body(errorResponse);
        }
    }

    @PostMapping("/publish/{topic}")
    public ResponseEntity<EventResponse> publishEventToTopic(
            @PathVariable String topic,
            @RequestBody EventMessage eventMessage,
            @RequestHeader Map<String, String> allHeaders) {

        // Generate tracking-id if not present
        if (!allHeaders.containsKey("tracking-id")) {
            allHeaders = new LinkedHashMap<>(allHeaders);
            allHeaders.put("tracking-id", UUID.randomUUID().toString());
        }

        try {
            SendResult<String, String> result = eventProducerService
                    .sendEvent(topic, eventMessage, allHeaders)
                    .join();

            RecordMetadata metadata = result.getRecordMetadata();
            Map<String, String> includedHeaders = eventProducerService
                    .extractHeadersMap(result.getProducerRecord().headers());

            EventResponse response = new EventResponse(
                    "SUCCESS",
                    "Event published successfully to topic: " + topic,
                    metadata.topic(),
                    metadata.partition(),
                    metadata.offset(),
                    includedHeaders
            );

            return ResponseEntity.ok(response);

        } catch (Exception e) {
            EventResponse errorResponse = new EventResponse();
            errorResponse.setStatus("ERROR");
            errorResponse.setMessage("Failed to publish event: " + e.getMessage());
            return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR).body(errorResponse);
        }
    }

    @PostMapping("/publish/batch")
    public ResponseEntity<List<EventResponse>> publishBatchEvents(
            @RequestBody List<EventMessage> eventMessages,
            @RequestHeader(value = "tracking-id", required = false) String trackingId,
            @RequestHeader(value = "user-id", required = false) String userId,
            @RequestHeader Map<String, String> allHeaders) {

        // Ensure tracking-id exists for the batch
        String batchTrackingId = (trackingId != null && !trackingId.isBlank())
                ? trackingId : UUID.randomUUID().toString();
        allHeaders = new LinkedHashMap<>(allHeaders);
        allHeaders.put("tracking-id", batchTrackingId);

        List<EventResponse> responses = new ArrayList<>();
        Map<String, String> finalHeaders = allHeaders;

        for (int i = 0; i < eventMessages.size(); i++) {
            EventMessage eventMessage = eventMessages.get(i);

            // Add batch-specific headers to each message's custom headers
            if (eventMessage.getCustomHeaders() == null) {
                eventMessage.setCustomHeaders(new HashMap<>());
            }
            eventMessage.getCustomHeaders().put("batch-tracking-id", batchTrackingId);
            eventMessage.getCustomHeaders().put("batch-index", String.valueOf(i));
            eventMessage.getCustomHeaders().put("batch-size", String.valueOf(eventMessages.size()));

            try {
                SendResult<String, String> result = eventProducerService
                        .sendEvent(null, eventMessage, finalHeaders)
                        .join();

                RecordMetadata metadata = result.getRecordMetadata();
                Map<String, String> includedHeaders = eventProducerService
                        .extractHeadersMap(result.getProducerRecord().headers());

                responses.add(new EventResponse(
                        "SUCCESS",
                        "Event " + i + " published successfully",
                        metadata.topic(),
                        metadata.partition(),
                        metadata.offset(),
                        includedHeaders
                ));

            } catch (Exception e) {
                EventResponse errorResponse = new EventResponse();
                errorResponse.setStatus("ERROR");
                errorResponse.setMessage("Failed to publish event " + i + ": " + e.getMessage());
                responses.add(errorResponse);
            }
        }

        boolean allSuccess = responses.stream()
                .allMatch(r -> "SUCCESS".equals(r.getStatus()));

        HttpStatus status = allSuccess ? HttpStatus.OK : HttpStatus.MULTI_STATUS;
        return ResponseEntity.status(status).body(responses);
    }
}